const results = ($json.results || []);
if (!results.length) return [];  // nothing to process — workflow stops cleanly
return [{ json: results[0] }];   // process one at a time; next poll picks up the rest

const page = $json;
const props = page.properties || {};

const title    = (props['Job Title']?.title?.[0]?.text?.content || 'Unknown Title').trim();
const company  = (props['Company']?.rich_text?.[0]?.text?.content || 'Unknown Company').trim();
const roleType = props['Role Type']?.select?.name || 'Other';
const tags     = (props['Tags']?.multi_select || []).map(t => t.name);
const applyUrl = props['Apply URL']?.url || '';
const score    = props['Score']?.number || 0;
const fitSummary = props['Fit Summary']?.rich_text?.[0]?.text?.content || '';

function slugify(s, max) {
  return s.replace(/[^\w\s-]/g, '').replace(/\s+/g, ' ').trim().substring(0, max || 60);
}

const docDate     = new Date().toISOString().split('T')[0];
const folderName  = slugify(`${company} - ${title}`, 80);
const resumeTitle = `Resume - ${slugify(title, 45)} - ${company.substring(0, 25)} ${docDate}`;
const clTitle     = `Cover Letter - ${slugify(title, 40)} - ${company.substring(0, 25)} ${docDate}`;

return [{ json: {
  page_id:      page.id,
  title, company, role_type: roleType, tags, apply_url: applyUrl, score, fit_summary: fitSummary,
  folder_name: folderName, resume_title: resumeTitle, cl_title: clTitle,
}}];

const blocks = $json.results || [];
const pageInfo = $('Extract Page Info').first().json;

let inDesc = false;
const parts = [];

for (const block of blocks) {
  if (block.type === 'heading_2') {
    const text = block.heading_2?.rich_text?.[0]?.text?.content || '';
    if (text.includes('Full Job Description')) { inDesc = true; continue; }
    if (inDesc) break;
  }
  if (block.type === 'divider' && inDesc) break;
  if (inDesc && block.type === 'paragraph') {
    const t = block.paragraph?.rich_text?.[0]?.text?.content || '';
    if (t) parts.push(t);
  }
}

const description = parts.join('\n').substring(0, 5000);
return [{ json: { ...pageInfo, description } }];

const j = $json;
const resumeText = $json.resumeText || 'ERROR: resumeText missing from Resume Content node';

const tagsList = (j.tags || []).join(', ') || 'Not specified';
const desc     = (j.description || 'No description provided').substring(0, 3500);

const prompt = `You are a professional resume writer helping a senior network/infrastructure engineer tailor application materials for a specific job opening.

CANDIDATE BASE RESUME — USE THIS AS THE AUTHORITATIVE SOURCE:
${resumeText}

TARGET POSITION:
Title: ${j.title}
Company: ${j.company}
Role Type: ${j.role_type}
Key Skills Needed: ${tagsList}

JOB DESCRIPTION:
${desc}

INSTRUCTIONS:
Tailor the candidate's resume for this specific role. Keep all factual claims accurate — do not invent experience or credentials. Reorder emphasis within roles to highlight skills this job values, but PRESERVE ALL CONTENT. Preserve all specific metrics (1,200 routers, 100 servers, 1,600 rules, 350 locations, etc.).

CRITICAL — ALL 6 WORK HISTORY ENTRIES ARE REQUIRED in the experience array, in this exact order:
  1. Expeditors International (2025–Present) — include 4–5 bullets, emphasize most relevant work
  2. Umatilla Electric Cooperative (2020–2024) — include 4–5 bullets
  3. University of New Mexico Health Sciences Center (2016–2019) — include 3–4 bullets
  4. SAIC / Sandia National Laboratories (2014–2015) — include 2–3 bullets
  5. Cricket Communications (2012–2013) — include 2–3 bullets
  6. New Mexico Department of Information Technology (2006–2012) — include 2–3 bullets
DO NOT drop, combine, skip, or merge any of these 6 entries. Every one must appear.

Return ONLY valid JSON with no markdown fences, no extra text:

{
  "resume_sections": {
    "summary": "2–3 sentence professional summary written specifically for this role at this company",
    "core_competencies": ["12 competency phrases most relevant to this specific job — pick from the candidate's real skills, ordered by relevance to this role"],
    "experience": [
      {
        "company": "exact company name",
        "title": "exact title held",
        "dates": "date range",
        "location": "city, state or Remote",
        "bullets": ["achievement bullets rewritten to lead with skills this job values most — preserve all specific metrics"]
      }
    ],
    "technical_skills": "Technical skills paragraph with technologies most relevant to this role listed first — preserve all skills from the base resume, reordered by relevance",
    "education": "Bachelor of Applied Science, Information Security Systems | ITT Technical Institute\nBachelor of Applied Science, Electronics/Communications Engineering Technology | ITT Technical Institute\nAssociate of Applied Science, Computer/Electronics Engineering Technology | ITT Technical Institute\nCertifications: CCNA (2011, 97%) | BICSI Cable Installation"
  },
  "cover_letter": "Full 3–4 paragraph cover letter.\n\nParagraph 1 (hook): Open with something specific about ${j.company} and why this role is a strong fit — reference the company's industry, mission, or something distinctive.\n\nParagraph 2 (proof): Highlight 2–3 most relevant experiences with specific metrics. Connect directly to requirements in the job description.\n\nParagraph 3 (value): Explain the specific value the candidate brings — what problems they have solved that map directly to what this company needs.\n\nParagraph 4 (close): Professional closing with enthusiasm and call to action."
}`;

return [{ json: { ...j, prompt } }];

const resp = $input.first().json;
const j    = $('Build Prompt').first().json;

// DEBUG: expose what resp actually contains
const respKeys   = Object.keys(resp);
const hasContent = Array.isArray(resp.content);
const hasChoices = Array.isArray(resp.choices);
const anthropicRaw = hasContent ? (resp.content[0] || {}).text || '' : '';
const openaiRaw    = hasChoices ? ((resp.choices[0] || {}).message || {}).content || '' : '';
const raw = anthropicRaw || openaiRaw || '';

let result = {};
try {
  const BT = String.fromCharCode(96);
const BT3 = BT + BT + BT;
const cleaned = raw
  .replace(new RegExp(BT3 + 'json\s*', 'g'), '')
  .replace(new RegExp(BT3 + '\s*', 'g'), '')
  .trim();
  result = JSON.parse(cleaned);
} catch(e) {
  result = { resume_sections: null, cover_letter: raw || 'Parse failed.' };
}

const s = result.resume_sections;

// DEBUG: if still failing, surface detail in the resume doc
const debugInfo = [
  'resp keys: ' + respKeys.join(', '),
  'hasContent: ' + hasContent,
  'hasChoices: ' + hasChoices,
  'raw length: ' + raw.length,
  'raw start:  ' + raw.substring(0,120),
].join('\n');

const DARK_BLUE = { color: { rgbColor: { red: 0.110, green: 0.239, blue: 0.376 } } };
const MED_GRAY  = { color: { rgbColor: { red: 0.40,  green: 0.40,  blue: 0.40  } } };

let resumeText    = '';
let docPos        = 1;
const fmtRequests = [];

function addPart(text, textStyle, align) {
  if (!text) return;
  const start = docPos;
  resumeText += text;
  docPos += text.length;
  const end = docPos;
  if (textStyle) {
    let styleEnd = end;
    for (let i = text.length - 1; i >= 0 && text[i] === '\n'; i--) styleEnd--;
    if (styleEnd > start) {
      const ts = {}, fields = [];
      if (textStyle.bold      !== undefined) { ts.bold   = textStyle.bold;   fields.push('bold'); }
      if (textStyle.italic    !== undefined) { ts.italic = textStyle.italic; fields.push('italic'); }
      if (textStyle.fontSize  !== undefined) { ts.fontSize = { magnitude: textStyle.fontSize, unit: 'PT' }; fields.push('fontSize'); }
      if (textStyle.foregroundColor) { ts.foregroundColor = textStyle.foregroundColor; fields.push('foregroundColor'); }
      if (fields.length) fmtRequests.push({ updateTextStyle: { range: { startIndex: start, endIndex: styleEnd }, textStyle: ts, fields: fields.join(',') }});
    }
  }
  if (align) fmtRequests.push({ updateParagraphStyle: { range: { startIndex: start, endIndex: end }, paragraphStyle: { alignment: align }, fields: 'alignment' }});
}

function sectionHeader(title) {
  addPart(title + '\n', { bold: true, fontSize: 11, foregroundColor: DARK_BLUE });
}

if (s) {
  addPart('GADGET\n', { bold: true, fontSize: 18 }, 'CENTER');
  addPart('Walla Walla, WA  •  505.926.1010  •  your.email@example.com  •  gadget.com\n', { fontSize: 10 }, 'CENTER');
  addPart('\n');
  addPart('Tailored for: ' + j.title + ' — ' + j.company + '\n', { italic: true, fontSize: 9, foregroundColor: MED_GRAY }, 'CENTER');
  addPart('\n');
  sectionHeader('PROFESSIONAL SUMMARY');
  addPart((s.summary || '') + '\n', { fontSize: 10 });
  addPart('\n');
  sectionHeader('CORE COMPETENCIES');
  addPart((s.core_competencies || []).join('  •  ') + '\n', { fontSize: 10 });
  addPart('\n');
  sectionHeader('PROFESSIONAL EXPERIENCE');
  for (const exp of (s.experience || [])) {
    addPart((exp.company || '').toUpperCase() + '\n', { bold: true, fontSize: 11 });
    const loc = exp.location ? '  —  ' + exp.location : '';
    addPart((exp.title || '') + loc + '  |  ' + (exp.dates || '') + '\n', { italic: true, fontSize: 10 });
    for (const bullet of (exp.bullets || [])) {
      addPart('    •  ' + bullet + '\n', { fontSize: 10 });
    }
    addPart('\n');
  }
  sectionHeader('TECHNICAL SKILLS');
  addPart((s.technical_skills || '') + '\n', { fontSize: 10 });
  addPart('\n');
  sectionHeader('EDUCATION & CERTIFICATIONS');
  addPart((s.education || '') + '\n', { fontSize: 10 });
} else {
  addPart('=== RESUME GENERATION DEBUG ===\n', { bold: true, fontSize: 12 });
  addPart(debugInfo + '\n', { fontSize: 10 });
  addPart('\n=== RAW CLAUDE OUTPUT (first 2000 chars) ===\n', { bold: true, fontSize: 10 });
  addPart((raw || '(empty)').substring(0, 2000) + '\n', { fontSize: 9 });
}

const coverLetterText = [
  j.company, 'Re: ' + j.title,
  'Date: ' + new Date().toLocaleDateString('en-US', { year:'numeric', month:'long', day:'numeric' }),
  '', result.cover_letter || 'Cover letter generation failed.', '',
  'Sincerely,', 'Gadget',
  'your.email@example.com  |  505.926.1010  |  gadget.com',
].join('\n');

const resumeBatchBody = JSON.stringify({ requests: [{ insertText: { location: { index: 1 }, text: resumeText } }, ...fmtRequests] });
const clBatchBody = JSON.stringify({ requests: [{ insertText: { location: { index: 1 }, text: coverLetterText } }] });

return [{ json: { ...j, resume_text: resumeText, cover_letter_text: coverLetterText,
  resume_batch_body: resumeBatchBody, cl_batch_body: clBatchBody } }];

const d       = $('Parse Docs').first().json;
const resume  = $('Create Resume Doc').first().json;
const cl      = $('Create Cover Letter Doc').first().json;
const folder  = $('Create App Folder').first().json;

const folderId  = folder.id;
const folderUrl = 'https://drive.google.com/drive/folders/' + folderId;
const resumeUrl = 'https://docs.google.com/document/d/' + resume.documentId + '/edit';
const clUrl     = 'https://docs.google.com/document/d/' + cl.documentId + '/edit';

const discordMsg = [
  '\uD83D\uDCC4 **Application docs ready!**',
  `**${d.title}** @ ${d.company}`,
  `Score: ${d.score}  \u2022  ${d.role_type}`,
  '',
  `\uD83D\uDCC1 [Application Folder](${folderUrl})`,
  `\uD83D\uDCDD [Tailored Resume](${resumeUrl})`,
  `\u2709\uFE0F [Cover Letter](${clUrl})`,
  '',
  `Apply: ${d.apply_url || '(see Notion page)'}`,
].join('\n');

return [{ json: {
  page_id:      d.page_id,
  discord_msg:  discordMsg,
  notion_patch: JSON.stringify({
    properties: {
      'Status':       { select: { name: 'Docs Ready' } },
      'Drive Folder': { url: folderUrl },
    }
  }),
}}];

// Prevents double-processing if the 10-min poll fires while a job is mid-run.
// Uses per-workflow static data (free, built-in, survives restarts).
const state = $getWorkflowStaticData('global');
const pageId = $json.id;
const inProgress = state.processing || {};
const staleAfterMs = 30 * 60 * 1000; // 30 min safety release

// Clear stale locks first
const now = Date.now();
for (const [pid, ts] of Object.entries(inProgress)) {
  if (now - ts > staleAfterMs) delete inProgress[pid];
}

if (inProgress[pageId]) {
  return []; // already being processed — skip
}

inProgress[pageId] = now;
state.processing = inProgress;

return [{ json: $json }];

// Release the processing lock for this page so future polls can re-process
// if the job ever gets reset back to 'Applying' status.
const state = $getWorkflowStaticData('global');
const pageId = $('Guard Duplicate').first().json.id;
const inProgress = state.processing || {};
delete inProgress[pageId];
state.processing = inProgress;
return [{ json: { cleared: pageId } }];
